(function(g){g.SD_ANNUAL={"varshesh":{"sun":{"en":"A year ruled by the Sun — themes of authority, recognition, health and self-assertion dominate. Leadership opportunities, dealings with government or seniors, and a stronger sense of purpose mark the twelve months. Guard against ego and pace your energy.","hi":"यह साल सूर्य के अधीन है — पद, पहचान, सेहत और अपनी बात रखने के विषय सामने रहेंगे। नेतृत्व के मौक़े, सरकारी या बड़े लोगों से काम, और अपने मक़सद को लेकर साफ़ सोच इन बारह महीनों की पहचान है। अहं से बचिए और ऊर्जा सोच-समझकर ख़र्च कीजिए।"},"moon":{"en":"A year ruled by the Moon — emotions, home, mother, and public connection take centre stage. It is a year of nurturing and being nurtured, of travel and shifting moods. Protect your peace of mind and stay close to well-wishers.","hi":"यह साल चंद्र के अधीन है — भावनाएँ, घर, माँ और लोगों से जुड़ाव केंद्र में रहेंगे। यह साल किसी का सहारा बनने और सहारा पाने का है, यात्रा और बदलते मन का भी। अपने मन की शांति सँभालिए और शुभचिंतकों के क़रीब रहिए।"},"mars":{"en":"A year ruled by Mars — energy, courage, property and bold action define it. Excellent for initiatives requiring drive, competition and technical skill; take care with anger, haste and disputes. Channel the fire into disciplined effort.","hi":"यह साल मंगल के अधीन है — ऊर्जा, हिम्मत, ज़मीन-जायदाद और बड़े क़दम इसकी पहचान हैं। जिन कामों में दम, मुक़ाबला और तकनीकी हुनर चाहिए, उनके लिए बढ़िया साल; ग़ुस्से, जल्दबाज़ी और झगड़ों से बचिए। इस जोश को अनुशासन के साथ काम में लगाइए।"},"mercury":{"en":"A year ruled by Mercury — communication, learning, business and intellect flourish. A fine year for study, trade, writing and negotiation; ideas flow and networks expand. Stay organized and verify details in all agreements.","hi":"यह साल बुध के अधीन है — बातचीत, पढ़ाई, व्यापार और बुद्धि से जुड़े काम फलते हैं। पढ़ाई, कारोबार, लेखन और सौदेबाज़ी के लिए बढ़िया साल; नए विचार आएँगे और संपर्क बढ़ेंगे। हिसाब-किताब व्यवस्थित रखिए और हर समझौते की बारीकी जाँच लीजिए।"},"jupiter":{"en":"A year ruled by Jupiter — the most auspicious of year lords. Wisdom, growth, good fortune, teachers, finance and family blessings flow generously. A wonderful year to expand, learn, marry, or begin ventures. Give generously and act with faith.","hi":"यह साल गुरु के अधीन है — सभी वर्ष-स्वामियों में सबसे शुभ। ज्ञान, तरक़्क़ी, भाग्य, गुरुजन, पैसा और पारिवारिक आशीर्वाद खुलकर मिलते हैं। कुछ बड़ा शुरू करने, पढ़ने, शादी करने या नया काम आरंभ करने के लिए बहुत अच्छा साल। खुले हाथ से दान कीजिए और भरोसे के साथ आगे बढ़िए।"},"venus":{"en":"A year ruled by Venus — relationships, comforts, arts, and financial pleasures blossom. Romance, marriage, beauty, luxury and creative pursuits are favoured; enjoyment comes easily. Savour in moderation and invest in lasting beauty.","hi":"यह साल शुक्र के अधीन है — रिश्ते, सुख-सुविधा, कला और आर्थिक ख़ुशियाँ बढ़ती हैं। प्यार, शादी, सुंदरता, आराम और रचनात्मक काम के लिए अनुकूल समय; ख़ुशी सहज मिलती है। संयम रखिए और जो चीज़ें लंबे समय तक साथ दें, उन्हीं में पैसा लगाइए।"},"saturn":{"en":"A year ruled by Saturn — discipline, responsibility, and lasting foundations are the themes. Progress is steady rather than swift; hard work now builds durable results. Protect health, honour commitments, and avoid shortcuts. Patience is richly rewarded.","hi":"यह साल शनि के अधीन है — अनुशासन, ज़िम्मेदारी और टिकाऊ नींव इसके मुख्य स्वर हैं। तरक़्क़ी तेज़ नहीं, स्थिर रहेगी; आज की मेहनत आगे चलकर पक्का फल देती है। सेहत सँभालिए, किए गए वादे निभाइए और शॉर्टकट से दूर रहिए। धैर्य का यहाँ पूरा इनाम मिलता है।"},"rahu":{"en":"A year ruled by Rahu — ambition, foreign matters, technology and unconventional gains rise. Sudden opportunities and unusual paths appear; the year rewards boldness tempered with ethics. Verify shortcuts and stay grounded amid rapid change.","hi":"यह साल राहु के अधीन है — महत्वाकांक्षा, विदेश, तकनीक और लीक से हटकर फ़ायदे बढ़ते हैं। अचानक मौक़े और अलग तरह के रास्ते खुलेंगे; ईमानदारी के साथ उठाई गई हिम्मत इस साल रंग लाती है। शॉर्टकट परख लीजिए और तेज़ बदलाव के बीच ज़मीन से जुड़े रहिए।"},"ketu":{"en":"A year ruled by Ketu — introspection, spirituality, research and letting go come to the fore. Material matters may feel secondary to inner growth; it is a fine year for sadhana, study and simplification. Trust your intuition and release what no longer serves.","hi":"यह साल केतु के अधीन है — आत्म-चिंतन, अध्यात्म, रिसर्च और मोह छोड़ना आगे आते हैं। भौतिक बातें भीतर के विकास के आगे छोटी लग सकती हैं; साधना, अध्ययन और ज़िंदगी को सरल बनाने के लिए बढ़िया साल। अपने मन की आवाज़ पर भरोसा कीजिए और जो अब काम का नहीं, उसे जाने दीजिए।"}},"muntha":{"1":{"en":"The Muntha in the 1st house energizes your whole year — vitality, initiative and personal prominence are strong. A year to lead and to put yourself forward.","hi":"मुंथा पहले भाव में है, जो पूरे साल को ऊर्जा देती है — सेहत, पहल और अपनी पहचान मज़बूत रहेगी। यह साल आगे बढ़कर नेतृत्व करने और ख़ुद को सामने रखने का है।"},"2":{"en":"The Muntha in the 2nd house turns the year toward wealth, family and speech — earnings and savings gain focus, and family matters are prominent.","hi":"मुंथा दूसरे भाव में है, तो साल का रुख़ पैसे, परिवार और वाणी की ओर रहेगा — कमाई और बचत पर ध्यान बढ़ेगा, और परिवार से जुड़े मामले सामने रहेंगे।"},"3":{"en":"The Muntha in the 3rd house favours courage, effort and communication — a year of initiative, short travels and progress through your own drive.","hi":"मुंथा तीसरे भाव में है, जो हिम्मत, मेहनत और बातचीत के पक्ष में है — पहल करने, छोटी यात्राओं और अपने दम पर आगे बढ़ने का साल।"},"4":{"en":"The Muntha in the 4th house centres the year on home, property, mother and inner peace — matters of residence and emotional foundation come forward.","hi":"मुंथा चौथे भाव में है, तो साल का केंद्र घर, ज़मीन-जायदाद, माँ और मन की शांति रहेगा — रहने की जगह और भावनात्मक नींव से जुड़ी बातें सामने आएँगी।"},"5":{"en":"The Muntha in the 5th house brings creativity, children, learning and romance into focus — an auspicious placement for joy, education and self-expression.","hi":"मुंथा पाँचवें भाव में है, जो रचनात्मकता, संतान, पढ़ाई और प्यार को केंद्र में लाती है — ख़ुशी, शिक्षा और ख़ुद को व्यक्त करने के लिए शुभ स्थिति।"},"6":{"en":"The Muntha in the 6th house emphasizes work, service and overcoming obstacles — a year to defeat rivals and resolve debts through steady effort; guard health.","hi":"मुंथा छठे भाव में है, जो काम, सेवा और मुश्किलों पर जीत को आगे लाती है — लगातार मेहनत से विरोधियों पर जीत और क़र्ज़ से छुटकारा; सेहत का ध्यान रखिए।"},"7":{"en":"The Muntha in the 7th house highlights partnerships, marriage and public dealings — relationships and collaborations take centre stage this year.","hi":"मुंथा सातवें भाव में है, जो साझेदारी, शादी और लोगों से व्यवहार को उभारती है — इस साल रिश्ते और मिलकर किए गए काम केंद्र में रहेंगे।"},"8":{"en":"The Muntha in the 8th house asks for caution and consolidation — a year of transformation where patience, prudence and health-care matter most. Avoid big risks.","hi":"मुंथा आठवें भाव में है, जो सावधानी और सँभालने की माँग करती है — बदलाव का साल, जहाँ धैर्य, समझदारी और सेहत का ध्यान सबसे ज़रूरी है। बड़े जोखिम टालिए।"},"9":{"en":"The Muntha in the 9th house is highly fortunate — fortune, higher learning, dharma and travel are blessed. A year of luck, wisdom and meaningful journeys.","hi":"मुंथा नवें भाव में है, जो बहुत भाग्यशाली है — भाग्य, आगे की पढ़ाई, धर्म और यात्रा पर कृपा रहेगी। यह क़िस्मत, ज्ञान और सार्थक यात्राओं का साल है।"},"10":{"en":"The Muntha in the 10th house favours career and status — professional achievement, recognition and public standing rise. An excellent year for work goals.","hi":"मुंथा दसवें भाव में है, जो करियर और पद के पक्ष में है — काम में उपलब्धि, पहचान और समाज में स्थिति बढ़ती है। नौकरी-कारोबार के लक्ष्यों के लिए बढ़िया साल।"},"11":{"en":"The Muntha in the 11th house is excellent for gains — income, fulfilled wishes, networks and elder siblings prosper. One of the most favourable placements for the year.","hi":"मुंथा ग्यारहवें भाव में है, जो लाभ के लिए बहुत अच्छी है — आमदनी, पूरी होती इच्छाएँ, संपर्क और बड़े भाई-बहन का साथ फलता है। साल की सबसे अनुकूल स्थितियों में से एक।"},"12":{"en":"The Muntha in the 12th house turns toward expenses, foreign matters, spirituality and rest — a year for inner work, letting go, and careful handling of resources.","hi":"मुंथा बारहवें भाव में है, तो रुख़ ख़र्च, विदेश, अध्यात्म और आराम की ओर रहेगा — भीतर के काम, मोह छोड़ने और पैसे को सँभालकर चलाने का साल।"}},"labels":{"title":{"en":"Annual Forecast","hi":"वार्षिक भविष्यफल"},"subtitle":{"en":"Your year ahead — Varshaphal solar-return analysis","hi":"आपका आने वाला साल — वर्षफल कुंडली के आधार पर"},"forYear":{"en":"For the year","hi":"साल"},"summary":{"en":"Your Year at a Glance","hi":"एक नज़र में आपका साल"},"chart":{"en":"Varshaphal Chart","hi":"वर्षफल कुंडली"},"varshaLagna":{"en":"Annual Ascendant (Varsha Lagna)","hi":"वर्ष लग्न"},"yearLord":{"en":"Year Lord (Varshesh)","hi":"वर्ष का स्वामी (वर्षेश)"},"munthaLabel":{"en":"Muntha","hi":"मुंथा"},"solarReturn":{"en":"Solar Return moment","hi":"सूर्य के लौटने का समय"},"yearTheme":{"en":"The Character of Your Year","hi":"आपके साल का मिज़ाज"},"munthaTheme":{"en":"Where the Year's Focus Falls","hi":"साल का ध्यान कहाँ रहेगा"},"months":{"en":"Month-by-Month Outlook","hi":"महीने-दर-महीने"},"bestDates":{"en":"Auspicious Dates This Year","hi":"इस साल के शुभ दिन"},"remedies":{"en":"Remedies for the Year","hi":"साल के लिए उपाय"},"favourable":{"en":"Favourable","hi":"अनुकूल"},"steady":{"en":"Steady","hi":"सामान्य"},"care":{"en":"Take care","hi":"सँभलकर"},"method":{"en":"This forecast is cast from your Varshaphal — the chart of the exact moment the Sun returned to its birth position this year (Tajika tradition) — combined with your running dasha and monthly transits. Placements are verifiable against your free Kundli report.","hi":"यह भविष्यफल आपकी वर्षफल कुंडली से बना है — यानी उस ठीक पल की कुंडली जब इस साल सूर्य आपकी जन्म-स्थिति पर लौटा (ताजिक पद्धति) — साथ में आपकी चल रही दशा और महीने के गोचर भी जोड़े गए हैं। सभी स्थितियाँ निःशुल्क कुंडली रिपोर्ट से मिलाई जा सकती हैं।"},"disclaimer":{"en":"Offered in the spirit of tradition for reflection and planning. Renew each year for a fresh Varshaphal. Your effort and choices shape the year.","hi":"परंपरा की भावना से, सोच-विचार और योजना के लिए प्रस्तुत। हर साल नई वर्षफल कुंडली बनवाइए। साल कैसा बीतेगा, यह आपकी मेहनत और फ़ैसलों से तय होता है।"}},"monthHint":{"sun":{"focusEn":"authority and health","oppEn":"recognition at work","avoidEn":"ego clashes","focusHi":"पद और सेहत","oppHi":"काम में पहचान","avoidHi":"अहं की टक्कर"},"moon":{"focusEn":"home and emotions","oppEn":"nurturing connections","avoidEn":"overthinking","focusHi":"घर और भावनाएँ","oppHi":"अपनों से जुड़ाव","avoidHi":"ज़्यादा सोचना"},"mars":{"focusEn":"energy and property","oppEn":"bold initiatives","avoidEn":"arguments and haste","focusHi":"ऊर्जा और ज़मीन-जायदाद","oppHi":"बड़े क़दम","avoidHi":"बहस और जल्दबाज़ी"},"mercury":{"focusEn":"communication and finances","oppEn":"networking and deals","avoidEn":"careless paperwork","focusHi":"बातचीत और पैसा","oppHi":"संपर्क और सौदे","avoidHi":"काग़ज़ी काम में लापरवाही"},"jupiter":{"focusEn":"growth and learning","oppEn":"expansion and guidance","avoidEn":"overcommitment","focusHi":"तरक़्क़ी और सीखना","oppHi":"विस्तार और मार्गदर्शन","avoidHi":"ज़्यादा वादे करना"},"venus":{"focusEn":"relationships and comfort","oppEn":"romance and creativity","avoidEn":"overindulgence","focusHi":"रिश्ते और सुख","oppHi":"प्यार और रचनात्मकता","avoidHi":"ज़रूरत से ज़्यादा ख़र्च"},"saturn":{"focusEn":"work and discipline","oppEn":"steady foundations","avoidEn":"shortcuts and delays","focusHi":"काम और अनुशासन","oppHi":"मज़बूत नींव","avoidHi":"शॉर्टकट और देरी"},"rahu":{"focusEn":"ambition and new paths","oppEn":"foreign and tech gains","avoidEn":"risky shortcuts","focusHi":"महत्वाकांक्षा और नए रास्ते","oppHi":"विदेश और तकनीक से लाभ","avoidHi":"जोखिम भरे शॉर्टकट"},"ketu":{"focusEn":"reflection and research","oppEn":"spiritual focus","avoidEn":"scattered energy","focusHi":"चिंतन और रिसर्च","oppHi":"आध्यात्मिक ध्यान","avoidHi":"बिखरी हुई ऊर्जा"}},"mLabels":{"focus":{"en":"Focus","hi":"ध्यान"},"opp":{"en":"Opportunity","hi":"मौक़ा"},"avoid":{"en":"Avoid","hi":"बचें"}}};})(typeof window!=='undefined'?window:global);
